import React from 'react';
import { TeamStanding } from '../types';
import { ViewMode } from './EventView';

interface TeamRankingsProps {
  standings: TeamStanding[];
  viewMode: ViewMode;
}

const RANK_ICONS = ['🥇', '🥈', '🥉'];

const TeamRankings: React.FC<TeamRankingsProps> = ({ standings, viewMode }) => {
  const sorted = [...standings].sort((a, b) => {
    const aW = viewMode === 'predicted' ? a.predictedWins : a.actualWins;
    const bW = viewMode === 'predicted' ? b.predictedWins : b.actualWins;
    if (bW !== aW) return bW - aW;
    return b.opr - a.opr;
  });

  return (
    <div className="team-rankings">
      <h3 className="panel-title">
        {viewMode === 'predicted' ? '🔮 Predicted Rankings' : '📊 Actual Rankings'}
      </h3>
      <div className="rankings-scroll">
        <table className="rankings-table">
          <thead>
            <tr>
              <th>#</th>
              <th>Team</th>
              <th>W</th>
              <th>L</th>
              <th>T</th>
              <th>OPR</th>
            </tr>
          </thead>
          <tbody>
            {sorted.map((team, idx) => {
              const wins   = viewMode === 'predicted' ? team.predictedWins   : team.actualWins;
              const losses = viewMode === 'predicted' ? team.predictedLosses : team.actualLosses;
              const ties   = viewMode === 'predicted' ? team.predictedTies   : team.actualTies;

              return (
                <tr
                  key={team.teamNumber}
                  className={idx < 3 ? `top-row rank-${idx + 1}` : ''}
                >
                  <td className="cell-rank">
                    {idx < 3 ? RANK_ICONS[idx] : idx + 1}
                  </td>
                  <td className="cell-team">#{team.teamNumber}</td>
                  <td className="cell-w">{wins}</td>
                  <td className="cell-l">{losses}</td>
                  <td className="cell-t">{ties}</td>
                  <td className="cell-opr">{team.opr.toFixed(1)}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TeamRankings;
